import json
import os
import subprocess
import tempfile
import pytest

AC_UID = "ac5_baseline_import_idempotent"
AC_TYPE = "data"


def test_AC5():
    """
    GIVEN: logs/lifecycle.jsonl is empty (or has partial imports)
    WHEN:  bash scripts/lifecycle-baseline-import.sh is invoked twice consecutively
    THEN:  second invocation appends zero lines (all agents already have a lifecycle entry after first run)
    """
    repo = "/dev/shm/dev-workspace/dot-claude"
    fd_lc, tmp_lifecycle = tempfile.mkstemp(suffix=".jsonl", prefix="test-ac5-lc-")
    fd_sc, tmp_scores = tempfile.mkstemp(suffix=".json", prefix="test-ac5-sc-")
    try:
        os.close(fd_lc)  # start empty
        # Build minimal agent-scores.json with all 21 canonical agents at score 42
        canonical = [
            "ba", "dev", "qa",
            "ui-specialist", "architect", "product-owner", "user", "pm",
            "changelog-analyst", "push-analyst", "merge-analyst", "pull-analyst",
            "cleanliness-inspector", "style-inspector", "prompt-inspector",
            "rule-inspector", "git-edge-case-analyst", "cleaner",
            "test-validator", "test-executor", "spec",
        ]
        data = {"global": {"agents": {ag: {"score": 42, "rank": "Skilled Craftsman", "history": []} for ag in canonical}}}
        with os.fdopen(fd_sc, "w") as f:
            json.dump(data, f)

        # First run
        r1 = subprocess.run(
            ["bash", "scripts/lifecycle-baseline-import.sh",
             "--lifecycle-file", tmp_lifecycle, "--scores-file", tmp_scores],
            capture_output=True, text=True, cwd=repo,
        )
        assert r1.returncode == 0, f"First baseline-import failed: {r1.stderr}"
        with open(tmp_lifecycle) as f:
            after_first = len([l for l in f if l.strip()])
        assert after_first == 21, f"Expected 21 lines after first run, got {after_first}"

        # Second run (idempotent)
        r2 = subprocess.run(
            ["bash", "scripts/lifecycle-baseline-import.sh",
             "--lifecycle-file", tmp_lifecycle, "--scores-file", tmp_scores],
            capture_output=True, text=True, cwd=repo,
        )
        assert r2.returncode == 0, f"Second baseline-import failed: {r2.stderr}"
        with open(tmp_lifecycle) as f:
            after_second = len([l for l in f if l.strip()])
        assert after_second == after_first, (
            f"Second run appended {after_second - after_first} lines; expected 0 (idempotent)"
        )
    finally:
        for p in (tmp_lifecycle, tmp_scores):
            try:
                os.unlink(p)
            except OSError:
                pass
